try {
  const rawAiText = $json.candidates?.[0]?.content?.parts?.[0]?.text || $json.content?.parts?.[0]?.text || $json.text || '[]';
  // Limpieza robusta de Markdown JSON
  let cleanJsonText = rawAiText.replace(/^[\s\S]*?```(?:json)?\n?/i, ''); 
  cleanJsonText = cleanJsonText.replace(/\n?```[\s\S]*$/i, '');
  cleanJsonText = cleanJsonText.trim();

  if (!cleanJsonText.startsWith('[')) cleanJsonText = '[' + cleanJsonText;
  if (!cleanJsonText.endsWith(']')) cleanJsonText = cleanJsonText + ']';

  const results = JSON.parse(cleanJsonText);

  if (Array.isArray(results) && results.length > 0) {
    return results.map(p => ({ json: p }));
  } else {
     return [{ json: { name: 'Sin resultados', error: 'Gemini no encontró prospectos', role: 'N/A', industry: 'N/A', companyDomain: '' } }];
  }
} catch (e) {
  return [{ json: { name: 'Error de formato', error: e.message, role: 'Error', industry: 'N/A', companyDomain: '' } }];
}

const prospect = $('Separar Prospectos').item.json;
const hunterData = $json.data?.emails || [];
const pattern = $json.data?.pattern || '{first}.{last}';

let bestEmail = null;
let source = 'not_found';

const cleanStr = (str) => (str || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase().replace(/\s/g, '');
const fnRaw = prospect.name ? prospect.name.split(' ')[0] : '';
const lnRaw = prospect.name ? (prospect.name.split(' ').slice(1).join(' ') || '') : '';
const fn = cleanStr(fnRaw);
const ln = cleanStr(lnRaw.split(' ')[0]);

// 1. Match exacto en Hunter
if (hunterData.length > 0 && prospect.name) {
  const match = hunterData.find(e => 
    (fn && cleanStr(e.first_name).includes(fn)) || 
    (ln && cleanStr(e.last_name).includes(ln))
  );
  if (match) {
    bestEmail = match.value;
    source = 'hunter_io';
  }
}

// 2. Fallback IA: Adivinar correo con patrón del dominio
if (!bestEmail && fn && prospect.companyDomain) {
    let guessed = '';
    if (pattern.includes('{first}.{last}')) guessed = `${fn}.${ln}`;
    else if (pattern.includes('{f}{last}')) guessed = `${fn.charAt(0)}${ln}`;
    else if (pattern.includes('{first}{last}')) guessed = `${fn}${ln}`;
    else if (pattern.includes('{first}_{last}')) guessed = `${fn}_${ln}`;
    else if (pattern.includes('{last}{first}')) guessed = `${ln}${fn}`;
    else guessed = `${fn}.${ln}`;

    guessed = guessed.replace(/^\.|\.$/, '');
    bestEmail = `${guessed}@${prospect.companyDomain}`;
    source = 'ia_estimado';
}

return {
  ...prospect,
  email: bestEmail,
  emailSource: source,
  id: Math.random().toString(36).substring(2, 9)
};
